INSERT INTO `Flashcard` VALUES (1,1,'Software Assurance Lifecycle Models','Models that guide the development process by integrating security throughout the entire software lifecycle.',0,NULL),(2,1,'Software Assurance Maturity Models','Frameworks used by organizations to assess and improve their security processes over time.',1,NULL),(3,1,'Security Development Life Cycle (SDLC)','A process that integrates security measures at every stage of software development.',2,NULL),(4,1,'Attack Patterns','Structured methods used to understand and predict how an attacker might exploit a system.',3,NULL),(5,1,'Assurance Cases','Evidence-based arguments used to demonstrate a system\'s security and ensure no common vulnerabilities remain.',4,NULL),(6,1,'Architectural Risk Analysis','The evaluation of security feature designs (e.g., firewalls) to detect weaknesses before they are exploited.',5,NULL),(7,1,'White Box Testing','A testing method that thoroughly examines the internal workings of an application.',6,NULL),(8,1,'Black Box Testing','A testing method focusing on external behavior without insight into the application\'s internal code.',7,NULL),(9,1,'Penetration Testing','The practice of simulating attacks on software to identify security gaps.',8,NULL),(10,1,'BSIMM (Building Security In Maturity Model)','A framework for measuring and improving software security initiatives using real-world data from various organizations.',9,'known'),(15,2,'What is a software \"baseline\"?','An approved snapshot or \"official version\" of software configurations and code at a specific time, such as a production release.',0,NULL),(16,2,'What are the five steps of the formal Change Control Process?','1. Submission, 2. Evaluation/Impact Analysis, 3. Approval/Rejection, 4. Implementation, 5. Verification & Closure.',1,NULL),(17,2,'Define a \"Standard Change.\"','A routine, low-risk modification that is pre-approved and follows an established procedure.',2,NULL),(18,2,'What is an \"Emergency Change\"?','A critical fix that requires rapid action to address an urgent issue, often bypassing parts of the standard approval process.',3,'known'),(19,2,'Who typically makes change decisions in the Classical model versus the Agile model?','The Classical model uses a Change Control Board (CCB); the Agile model is led by the Product Owner.',4,'learning'),(20,2,'What is the \"Golden Thread\" in change control?','A path of traceability that connects change requests, approvals, testing, and deployments for audit and transparency purposes.',5,NULL),(21,2,'What is the primary goal of Release Management?','To deliver approved changes to users while minimizing risk, downtime, and impact on production stability.',6,NULL),(22,2,'What is a major risk associated with \"Big Bang\" releases?','They involve merging many complex changes at once, which often leads to significant system failures or crashes.',7,NULL),(23,2,'How does Blue-Green Deployment work?','It maintains two identical environments, allowing traffic to switch between them and enabling an instant rollback if issues occur.',8,NULL),(24,2,'What is a Canary Release?','A progressive delivery strategy where changes are rolled out to a small group of users first to test stability before a full deployment.',9,NULL),(25,2,'What are the main objectives of Change Control?','Preventing uncontrolled changes, ensuring traceability/accountability, evaluating risks, and maintaining regulatory compliance.',10,NULL),(26,2,'What occurs during the \"Evaluation and Impact Analysis\" phase of change control?','The proposed change undergoes a risk assessment to determine its potential effects on the system.',11,NULL),(27,3,'What is the primary goal of the AI-powered tool developed in this project?','To help students and lecturers summarize lecture notes from PDF or PowerPoint formats to enhance learning efficiency.',0,NULL),(28,3,'Which large language models (LLMs) are integrated into the tool?','Gemini, DeepSeek, and OpenAI.',1,NULL),(29,3,'What methodology was followed during the development process?','The Waterfall methodology, consisting of Requirement Analysis, System Design, Implementation, and Testing.',2,NULL),(30,3,'How does the tool handle text extraction from scanned documents?','By using Optical Character Recognition (OCR) technology.',3,NULL),(31,3,'What role does Natural Language Processing (NLP) play in the tool?','It enables the AI to understand and process human language for effective summarization.',4,NULL),(32,3,'Which frontend technologies were used to build the system?','React.js or Next.js along with TailwindCSS or MUI for styling.',5,NULL),(33,3,'What technologies make up the backend and database of the system?','Node.js and Express for the backend, and MySQL for data management.',6,NULL),(34,3,'Name the specific tools used for document processing and conversion.','dots.ocr (for text recognition) and pptx2json (for PowerPoint conversion).',7,NULL),(35,3,'What are the three existing systems used as benchmarks for this project?','Google NotebookLM, Scholarcy, and NoteGPT.',8,NULL),(36,3,'What is the benefit of saving summarized content in a database?','It allows for easy reference and reuse of the information by the users.',9,NULL),(37,3,'What are the primary target user roles for the tool?','Students and lecturers.',10,NULL),(38,3,'What is the expected impact of the tool on academic learning?','Reducing time spent reviewing materials and increasing learning quality by focusing on key content.',11,NULL),(39,4,'What is the primary goal of Software Assurance Lifecycle Models?','To guide the development process by integrating security throughout the entire software lifecycle.',0,NULL),(40,4,'What is the purpose of Software Assurance Maturity Models?','To help organizations assess and improve their security processes over time based on experience.',1,NULL),(41,4,'Why is early defect correction important in software development?','It saves time and resources and prevents security vulnerabilities from becoming costly to fix later.',2,NULL),(42,4,'What are \'Attack Patterns\' in software security?','Structured methods used to understand how an attacker might exploit a system to better predict and prevent attacks.',3,NULL),(43,4,'What is an \'Assurance Case\'?','A collection of evidence used to argue that a system is secure and free of common vulnerabilities.',4,NULL),(44,4,'What is architectural risk analysis?','The evaluation of design features (e.g., firewalls, IDS) to identify weaknesses before they are exploited.',5,NULL),(45,4,'Define White Box Testing.','A testing method that thoroughly examines the internal workings and code of an application.',6,NULL),(46,4,'Define Black Box Testing.','A testing method that focuses on the external behavior of an application without insight into its internal code.',7,NULL),(47,4,'What is the purpose of Penetration Testing?','To simulate real-world attacks on software to identify existing security gaps.',8,NULL),(48,4,'What is BSIMM?','The Building Security In Maturity Model, a framework that uses real-world data from over 130 organizations to establish security benchmarks.',9,NULL),(49,4,'What are two components of product security and risk management?','Gap assessment and security certifications.',10,NULL),(50,4,'What is the CVE database?','A repository that provides a list of known software vulnerabilities.',11,NULL),(51,4,'What does OWASP focus on?','Providing resources and guidelines for web application security.',12,NULL),(52,4,'What is the primary function of Secure Code Reviews?','Regularly inspecting code for vulnerabilities to ensure it adheres to secure coding standards.',13,NULL);
/*!40000 ALTER TABLE `Flashcard` ENABLE KEYS */;
UNLOCK TABLES;

