INSERT INTO `QuizAttempt` VALUES (1,4,1,2,10,'{\"0\": \"Traditional Definition\", \"1\": \"True\", \"2\": \"Guaranteed high financial returns\", \"3\": \"Debt financing involves giving up ownership in the business.\", \"4\": \"True\", \"5\": \"Majlis Amanah Rakyat (MARA)\", \"6\": \"Inability to raise large amounts of capital\", \"7\": \"True\", \"8\": \"It builds confidence with potential investors or lenders.\", \"9\": \"5-25 years\"}','2026-04-14 05:56:16.924',NULL),(2,4,3,2,10,'{\"0\": \"Startups, by definition, avoid \'bootstrapping\' with personal funds due to the inherent uncertainty of their business model, making them reliant on government grants.\", \"1\": \"True\", \"2\": \"i dunno\", \"3\": \"Debt financing is always preferred by venture capitalists as it scales better with technology startups, whereas equity financing is limited to personal funds and family investments.\", \"4\": \"SME entrepreneurs for general business loans and equipment\", \"5\": \"False\", \"6\": \"True\"}','2026-04-14 10:25:30.312',NULL),(3,4,5,4,10,'{\"0\": \"Structure-based testing\", \"1\": \"Data Flow Coverage\", \"2\": \"It is too difficult to calculate for small programs.\", \"3\": \"Condition-Based Testing\", \"4\": \"The sequence of executable statements in a graph.\", \"5\": \"Control Flow Testing\", \"6\": \"The number of potential test cases grows exponentially with code complexity.\", \"7\": \"The ratio of executed statements to total statements\", \"8\": \"It provides too much data for coverage metrics.\", \"9\": \"Condition-Based Testing\"}','2026-05-17 06:09:58.845',NULL),(4,4,5,1,10,'{\"0\": \"Behavioral testing\", \"1\": \"Data Flow Coverage\", \"2\": \"It is too difficult to calculate for small programs.\", \"3\": \"Exploratory Testing\", \"4\": \"The informal guessing of likely error scenarios.\", \"5\": \"Static Analysis\", \"6\": \"It requires black-box testers to implement it.\", \"7\": \"The ratio of executed statements to total statements\", \"8\": \"It provides too much data for coverage metrics.\", \"9\": \"Condition-Based Testing\"}','2026-05-17 23:56:20.245','Simon Lee'),(5,13,2,3,10,'{\"0\": \"Focusing exclusively on non-technology endeavors\", \"1\": \"It eliminates the need for regular interest payments\", \"2\": \"Angel Investors\", \"3\": \"To pay off high-interest bank loans\", \"4\": \"Personal credit cards for the founder\", \"5\": \"Giving up 100% ownership to a single entity\", \"6\": \"By being the first to pass laws encouraging equity-based crowdfunding\", \"7\": \"Using personal savings to fund a business\", \"8\": \"It is a requirement by Malaysia\'s Securities Commission\", \"9\": \"Dotcoms or online businesses\"}','2026-06-04 06:57:07.901','Alexc');
