INSERT INTO `SummaryHighlight` VALUES (3,4,2,'learning unit focuses on the critical aspects of funding and financing for new entrepreneurial ventures','2026-03-28 08:40:44.607','#fef08a','summary',NULL),(5,4,2,'Identifying factors co','2026-03-28 08:49:51.455','#93c5fd','summary',NULL),(6,4,2,'Generally newly-created organizations in development and research phases','2026-03-28 14:55:20.766','#f0abfc','summary',NULL),(10,4,5,'comprehensive exploration into the','2026-04-08 00:09:33.161','#fef08a','summary',NULL),(11,4,9,'powerful AI-driven slide generation','2026-05-02 08:25:34.655','#fdba74','summary',NULL),(12,4,9,'nd creativity in presentation desi','2026-05-15 13:21:47.182','#fef08a','summary',NULL),(13,4,15,'Key roles in security governance include the Board of Directors, C-level officers like the CIO/CISO, a Security Governance Committee, and internal audit teams. Frameworks: International f','2026-05-20 07:24:10.874','#fef08a','summary',NULL),(17,4,16,'tem being tested are known to the tester. This transparency is symbolized by the \"white\" in white-box, as opposed to a \"black-box\" approach where only inputs and outputs are visible, without insight into the internal working','2026-06-02 08:18:58.144','#86efac','chat',43),(18,4,16,'stem by focusing on its code and control flow, examining its functions, conditions, and paths to ensure that they are working as intended. It demands a good understanding of the source code to identify specific paths and areas th','2026-06-02 08:19:00.394','#f0abfc','chat',43),(19,4,6,'-term (a year or less), medium-term (1-5 years), or long-term (more than 5 yea','2026-06-03 06:46:18.953','#fef08a','summary',NULL),(20,4,7,'Security Requirements: Identify and document potential security requirements that align with the business objectives and regulatory needs. This includes understanding what security features the software needs and establishing criteria for secure develo','2026-06-04 11:23:23.148','#86efac','chat',51),(21,4,16,'chniques can instructors use to engage students in white-box technique discussions?','2026-06-05 14:14:55.314','#fef08a','chat',38),(22,4,16,'e, we delve into white-box testing, a testing methodology that involves evaluating a system based on its internal structures or workings. This approach, also known as structure-based testing, contrasts with black-box testing where the internal imp','2026-06-06 12:31:05.038','#fef08a','summary',NULL),(23,14,18,'Legacy Information Systems (LIS) are defined not merely by their age, but by their critical role in an organization combined with their resistance to change. As described in the lectur','2026-06-06 17:18:16.159','#fef08a','summary',NULL);
